import java.io.IOException;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize and escape user input before outputting it to the response
        String sanitizedInput = escapeHtml(userInput);

        // Output the sanitized user input to the response
        response.getWriter().write("<html><body>User Input: " + sanitizedInput + "</body></html>");
    }

    // Method to escape HTML special characters in user input
    private String escapeHtml(String input) {
        if (input == null) {
            return "";
        }

        return input
            .replace("&", "&amp;")
            .replace("<", "&lt;")
            .replace(">", "&gt;")
            .replace("\"", "&quot;")
            .replace("'", "&#39;");
    }

